const raw = items[0].json.output;

// Nếu không có dữ liệu
if (!raw || raw.trim() === "") {
  return [{
    json: {
      error: "No output found",
      raw
    }
  }];
}

// Bỏ các ký tự escape \" trong chuỗi
let cleaned = raw.trim();

// Loại bỏ dấu nháy thừa ở đầu/cuối nếu có
if (cleaned.startsWith('"') && cleaned.endsWith('"')) {
  cleaned = cleaned.slice(1, -1);
}

// Chuyển \" → "
cleaned = cleaned.replace(/\\"/g, '"');

let data;
try {
  data = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      error: "JSON parse failed",
      raw: cleaned
    }
  }];
}

// Trả về object chuẩn
return [{
  json: {
    patient_name: data.patient_name || "",
    phone: (data.phone || "").replace(/\D/g, ""), // chỉ lấy số
    date: data.date || "",
    shift: data.shift || "",
    time_range: data.time_range || ""
  }
}];
